def matmul(A, B):
    n = len(A)
    C = [[0]*n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            for k in range(n):
                C[i][j] += A[i][k] * B[k][j]
    return C

def count_triples(xs, target):
    c = 0
    n = len(xs)
    for i in range(n):
        for j in range(i+1, n):
            for k in range(j+1, n):
                if xs[i] + xs[j] + xs[k] == target:
                    c += 1
    return c

def power_set(xs):
    if not xs:
        return [[]]
    rest = power_set(xs[1:])
    return rest + [[xs[0]] + r for r in rest]

def subset_sum(xs, target):
    if target == 0:
        return True
    if not xs or target < 0:
        return False
    return subset_sum(xs[1:], target - xs[0]) or subset_sum(xs[1:], target)

def count_paths(n):
    if n <= 1:
        return 1
    return count_paths(n-1) + count_paths(n-2) + count_paths(n-3) if n >= 3 else count_paths(n-1) + count_paths(n-2)

def permutations(xs):
    if len(xs) <= 1:
        return [xs]
    out = []
    for i in range(len(xs)):
        rest = xs[:i] + xs[i+1:]
        for p in permutations(rest):
            out.append([xs[i]] + p)
    return out

def heaps_perm(a, k=None, out=None):
    if out is None:
        out, k = [], len(a)
    if k == 1:
        out.append(list(a))
        return out
    for i in range(k):
        heaps_perm(a, k-1, out)
        if k % 2 == 0:
            a[i], a[k-1] = a[k-1], a[i]
        else:
            a[0], a[k-1] = a[k-1], a[0]
    return out

def sum_digits(n):
    s = 0
    while n > 0:
        s += n % 10
        n //= 10
    return s
